  "caseStudy": "<table style=\"width:100%;max-width:340px;margin:10px auto;border-collapse:collapse;text-align:center;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Price (£)</th><th style=\"padding:6px;\">Quantity demanded (units)</th></tr>\n<tr><td style=\"padding:6px;\">10</td><td>80</td></tr>\n<tr><td style=\"padding:6px;\">20</td><td>70</td></tr>\n<tr><td style=\"padding:6px;\">30</td><td>60</td></tr>\n<tr><td style=\"padding:6px;\">40</td><td>50</td></tr>\n</table>",
