  "caseStudy": "<img src=\"/images/economics/2-6-tr-output-diagram-extracted.png\" alt=\"Diagram from the OCR exam paper: total revenue rising steeply from the origin, flattening between T and U, peaking at U, then falling to V, with output points S, T, U and V marked\" style=\"display:block;width:100%;max-width:440px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />",
