  "caseStudy": "<img src=\"/images/economics/3-1-real-national-output-diagram-extracted.png\" alt=\"Diagram from the OCR exam paper showing a country's real national output on the vertical axis against time on the horizontal axis from Year 0 to Year 10: the line rises overall, peaks and dips slightly just after Year 5, then rises again to its highest point at Year 10\" style=\"display:block;width:100%;max-width:480px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />",
