  "pageId": "economics:3-3-fair-distribution-of-income",
  "pageName": "3.3 Fair Distribution of Income",
  "source": "mcq",
  "type": "mcq",
  "marks": 1,
  "question": "Nazir saves 10% of his £30,000 income and owns a house worth £200,000. His wealth is...",
