  "caseStudy": "<table style=\"width:100%;max-width:420px;margin:12px auto;border-collapse:collapse;text-align:left;font-size:14px;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Income (£ per year)</th><th style=\"padding:6px;\">Total tax paid (£ per year)</th></tr>\n<tr><td style=\"padding:6px;\">10 000</td><td style=\"padding:6px;\">1 000</td></tr>\n<tr><td style=\"padding:6px;\">20 000</td><td style=\"padding:6px;\">3 000</td></tr>\n<tr><td style=\"padding:6px;\">30 000</td><td style=\"padding:6px;\">10 000</td></tr>\n</table>",
